// JS port of src/cwsigfind/geo.py — country + state enrichment.
//
// Two paths, same as the Python side:
//   1. POTA's locationDesc ("US-AZ") → ("USA", "Arizona") via parseLocationDesc
//   2. Anything else → longest-prefix lookup against PREFIX_TO_COUNTRY.
//
// The prefix table itself is auto-generated by scripts/gen_prefixes.py so
// it stays in sync with the canonical Python table.

import {
  CA_PROVINCES,
  COUNTRY_NAMES,
  PREFIX_TO_COUNTRY,
  US_STATES,
} from "./prefixes.js";

export function countryName(code) {
  if (!code) return null;
  const up = String(code).toUpperCase();
  return COUNTRY_NAMES[up] || up;
}

export function parseLocationDesc(loc) {
  if (!loc) return [null, null];
  const raw = String(loc).toUpperCase().trim();

  // Multi-region POTA parks: "US-FL,US-GA" → state "FL/GA" inside USA.
  if (raw.includes(",")) {
    const segments = raw.split(",").map((s) => s.trim()).filter(Boolean);
    const countries = [];
    const states = [];
    for (const seg of segments) {
      const [c, s] = parseLocationDesc(seg);
      if (c && !countries.includes(c)) countries.push(c);
      if (s) states.push(s);
    }
    const country = countries[0] || null;
    let state = null;
    if (countries.length === 1) {
      const shortStates = segments
        .filter((seg) => seg.includes("-"))
        .map((seg) => seg.split("-", 2)[1]);
      state = shortStates.length ? shortStates.join("/") : null;
    } else {
      state = states.length ? states.join(", ") : null;
    }
    return [country, state];
  }

  const [cc, sub] = raw.includes("-") ? raw.split("-", 2) : [raw, null];
  const country = countryName(cc);
  let state = null;
  if (sub) {
    if (cc === "US") state = US_STATES[sub] || sub;
    else if (cc === "CA") state = CA_PROVINCES[sub] || sub;
    else state = sub;
  }
  return [country, state];
}

// Mirror of geo._normalize_callsign — strip "/P", "/4" etc. and pick the
// shortest portable-prefix segment when present ("VE3/W1ABC" → "VE3").
const COMMON_SUFFIXES = new Set(["P", "M", "MM", "AM", "QRP", "QRPP", "T", "STN"]);

function normalizeCallsign(call) {
  if (!call) return "";
  const s = String(call).toUpperCase().trim();
  if (!s.includes("/")) return s;
  const parts = s.split("/").filter(Boolean);
  if (!parts.length) return "";
  const head = parts[0];
  if (
    parts.length >= 2 &&
    head.length >= 1 &&
    head.length <= 3 &&
    !COMMON_SUFFIXES.has(head)
  ) {
    if ([...head].some((ch) => ch >= "0" && ch <= "9") || head.length >= 2) {
      return head;
    }
  }
  return parts[0];
}

export function countryForCallsign(call) {
  if (!call) return null;
  const cs = normalizeCallsign(call);
  if (!cs) return null;
  for (let plen = Math.min(4, cs.length); plen > 0; plen--) {
    const prefix = cs.slice(0, plen);
    if (PREFIX_TO_COUNTRY[prefix]) return PREFIX_TO_COUNTRY[prefix];
  }
  return null;
}

export function enrich(callsign, locationDesc) {
  let [country, state] = parseLocationDesc(locationDesc);
  if (!country && callsign) country = countryForCallsign(callsign);
  return [country, state];
}
